form.script:
const defaultHrs = parseFloat(document.getElementById('default_duration_hrs').value) || 12.0;

function calculateReturn() {
    const pickupInput = document.getElementById('pickup_datetime');
    const isExtended = document.getElementById('want_more_time').checked;
    const extraHrs = isExtended ? (parseInt(document.getElementById('extra_hours_input').value) || 0) : 0;
    const totalHrs = defaultHrs + extraHrs;

    // Time restriction enforcement: 7 AM - 11 PM, no minutes
    if (pickupInput.value) {
        let pickupDate = new Date(pickupInput.value);
        let modified = false;
        let now = new Date();
        if (pickupDate < now) {
            // Snap to current hour or next hour
            pickupDate = now;
            if (pickupDate.getMinutes() > 0) {
                pickupDate.setHours(pickupDate.getHours() + 1, 0, 0, 0);
            } else {
                pickupDate.setMinutes(0, 0, 0);
            }
            modified = true;
        }

        let hours = pickupDate.getHours();
        if (hours < 8) { 
            pickupDate.setHours(8, 0, 0, 0); 
            modified = true; 
        } else if (hours > 23) {
            pickupDate.setHours(23, 0, 0, 0); 
            modified = true; 
        } else if (pickupDate.getMinutes() !== 0) {
            // Force minutes to zero
            pickupDate.setMinutes(0, 0, 0);
            modified = true;
        }

        if (modified) {
            // Format back to YYYY-MM-DDTHH:MM for datetime-local
            const year = pickupDate.getFullYear();
            const month = String(pickupDate.getMonth() + 1).padStart(2, '0');
            const day = String(pickupDate.getDate()).padStart(2, '0');
            const h = String(pickupDate.getHours()).padStart(2, '0');
            const m = String(pickupDate.getMinutes()).padStart(2, '0');
            pickupInput.value = `${year}-${month}-${day}T${h}:${m}`;
        }
    }

    document.getElementById('duration_label').innerText = "Total Window: " + totalHrs + " Hrs";

    if (pickupInput.value) {
        const pickupDate = new Date(pickupInput.value);
        const returnDate = new Date(pickupDate.getTime() + (totalHrs * 60 * 60 * 1000));

        // Format for Odoo: YYYY-MM-DD HH:MM
        const year = returnDate.getFullYear();
        const month = String(returnDate.getMonth() + 1).padStart(2, '0');
        const day = String(returnDate.getDate()).padStart(2, '0');
        const hours = String(returnDate.getHours()).padStart(2, '0');
        const minutes = String(returnDate.getMinutes()).padStart(2, '0');

        const formattedDisplay = returnDate.toLocaleString([], { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit' });
        const formattedOdoo = `${year}-${month}-${day} ${hours}:${minutes}`;

        const displayReturnTime = document.getElementById('display_return_time');
        if (displayReturnTime) {
            displayReturnTime.innerText = formattedDisplay;
            displayReturnTime.classList.remove('opacity-50', 'italic');
        }
        document.getElementById('end_date_input').value = formattedOdoo;
    } else {
        const displayReturnTime = document.getElementById('display_return_time');
        if (displayReturnTime) {
            displayReturnTime.innerText = "Pick start time...";
            displayReturnTime.classList.add('opacity-50', 'italic');
        }
    }
}

document.getElementById('pickup_datetime').addEventListener('change', calculateReturn);
document.getElementById('want_more_time').addEventListener('change', (e) => {
    const container = document.getElementById('extra_hours_container');
    if (container) {
        if (e.target.checked) {
            container.classList.remove('hidden');
        } else {
            container.classList.add('hidden');
        }
    }
    calculateReturn();
});
document.getElementById('extra_hours_input').addEventListener('input', calculateReturn);

function incrementHours() { 
    const input = document.getElementById('extra_hours_input');
    input.value = parseInt(input.value) + 1;
    calculateReturn();
}
function decrementHours() { 
    const input = document.getElementById('extra_hours_input');
    if (parseInt(input.value) > 0) {
        input.value = parseInt(input.value) - 1;
        calculateReturn();
    }
}

t.script:
document.querySelectorAll('.add-to-cart-btn').forEach(btn => {
    btn.addEventListener('click', async (e) => {
        const target = e.currentTarget;
        const productId = target.dataset.productId;

        // Standard Odoo eCommerce Cart Bridge (JSONRPC 2.0 with CSRF)
        const response = await fetch('/shop/cart/update_json', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRF-Token': odoo.csrf_token || ''
            },
            body: JSON.stringify({
                jsonrpc: '2.0',
                params: { product_id: parseInt(productId), add_qty: 1 }
            })
        });
        const data = await response.json();
        if (data.result) {
            const cartQtyTotal = document.getElementById('cart_qty_total');
            if (cartQtyTotal) cartQtyTotal.innerText = data.result.cart_quantity;

            // Trigger Odoo's standard cart event to update the page header
            document.dispatchEvent(new CustomEvent('website_sale:cart_update', { detail: data.result }));

            if (target) {
                const oldText = target.innerText;
                target.classList.add('bg-green-500', 'text-white', 'border-green-500');
                target.innerText = 'Added!';
                setTimeout(() => {
                    target.classList.remove('bg-green-500', 'text-white', 'border-green-500');
                    target.innerText = oldText;
                }, 1000);
            }
        }
    });
});

document.querySelectorAll('.add-to-wishlist-btn').forEach(btn => {
    btn.addEventListener('click', async (e) => {
        const target = e.currentTarget;
        const productId = target.dataset.productId;

        const response = await fetch('/shop/wishlist/add', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRF-Token': odoo.csrf_token || ''
            },
            body: JSON.stringify({
                jsonrpc: '2.0',
                params: { product_id: parseInt(productId) }
            })
        });
        const data = await response.json();
        if (data.result) {
            target.querySelector('span').innerText = 'check'; // Success visual feedback
            target.classList.add('text-green-500');
            setTimeout(() => {
                target.querySelector('span').innerText = 'favorite';
                target.classList.remove('text-green-500');
            }, 1500);
        }
    });
});
